<style>
    .crud-page{min-height:100vh;padding:28px;background:radial-gradient(circle at 12% 0%,rgba(14,165,233,.2),transparent 26%),radial-gradient(circle at 88% 4%,rgba(249,115,22,.16),transparent 28%),linear-gradient(180deg,#020617,#0f172a 48%,#020617);color:#e5e7eb}.crud-hero,.crud-panel{border:1px solid rgba(255,255,255,.12);background:rgba(15,23,42,.82);box-shadow:0 28px 90px rgba(0,0,0,.35);backdrop-filter:blur(18px)}.crud-hero{display:flex;justify-content:space-between;gap:20px;align-items:flex-end;border-radius:30px;padding:30px;margin-bottom:18px}.crud-eyebrow{display:inline-flex;color:#38bdf8;font-size:12px;font-weight:900;letter-spacing:.2em;text-transform:uppercase}.crud-hero h1,.crud-panel h2{margin:8px 0;color:#fff;font-weight:950;letter-spacing:-.04em}.crud-hero h1{font-size:clamp(2rem,4vw,4rem)}.crud-hero p,.crud-muted{color:#b8c2d3;line-height:1.7}.crud-actions{display:flex;flex-wrap:wrap;gap:10px}.crud-button,.crud-link,.crud-danger{border:0;border-radius:999px;padding:10px 15px;font-weight:900;text-decoration:none}.crud-button{background:linear-gradient(135deg,#38bdf8,#f97316);color:#020617}.crud-link{background:#1e293b;color:#e5e7eb}.crud-danger{background:rgba(239,68,68,.16);color:#fecaca}.crud-panel{border-radius:24px;padding:22px}.crud-table{display:grid;gap:8px}.crud-row{display:grid;grid-template-columns:1.2fr 1fr 1fr 1fr auto;gap:12px;align-items:center;border:1px solid rgba(148,163,184,.18);border-radius:18px;padding:14px;background:rgba(2,6,23,.45)}.crud-row--head{color:#94a3b8;font-size:12px;font-weight:900;text-transform:uppercase;letter-spacing:.12em}.crud-row--empty{display:block;color:#94a3b8}.crud-row strong{display:block;color:#fff}.crud-row small{color:#94a3b8}.crud-form{display:grid;gap:16px}.crud-grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:16px}.crud-form label span{display:block;margin-bottom:6px;color:#cbd5e1;font-size:13px;font-weight:800}.crud-form input,.crud-form select,.crud-form textarea{width:100%;border:1px solid #334155;border-radius:16px;background:#020617;color:#fff;padding:11px 13px}.crud-error{margin-top:6px;color:#fca5a5;font-size:13px}.crud-alert{margin-bottom:14px;border:1px solid rgba(56,189,248,.35);border-radius:18px;background:rgba(14,165,233,.12);padding:12px 14px;color:#bae6fd}.crud-detail{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:12px}.crud-detail div{border:1px solid rgba(148,163,184,.18);border-radius:16px;padding:14px;background:rgba(2,6,23,.42)}.crud-detail span{display:block;color:#94a3b8;font-size:12px;font-weight:900;text-transform:uppercase}.crud-detail strong{display:block;margin-top:4px;color:#fff}.crud-pagination{margin-top:16px}.crud-inline-form{display:inline}.crud-stack{display:flex;gap:8px;align-items:center;justify-content:flex-end;flex-wrap:wrap}@media (max-width:900px){.crud-hero{display:block}.crud-grid,.crud-detail{grid-template-columns:1fr}.crud-row{grid-template-columns:1fr}.crud-row--head{display:none}.crud-stack{justify-content:flex-start}}
</style>
